const mode = $('Webhook').item.json.body.mode || 'A';
const message = $('Webhook').item.json.body.message || '';
const history = $('Webhook').item.json.body.history || '';
let sessionId = $('Webhook').item.json.body.session_id;
if (!sessionId) sessionId = 'scout-' + Date.now() + '-' + Math.random().toString(36).slice(2, 10);
const userId = $('Fetch User').item.json.user_id;
const clientId = $('Fetch User').item.json.client_id;
const priorities = $('Read Priorities').first().json.markdown || '';

const allSources = $('Read Sources').all().map(i => i.json);
const followed = allSources.filter(s => s.status === 'followed');
const naylisted = allSources.filter(s => s.status === 'naylisted');

let modeInstruction = '';
if (mode === 'A') {
  modeInstruction = 'MODE A — FIRST RUN. No priorities doc exists. Run the full discovery conversation (5-6 turns). Start neutral. Escalate only if early answers show it earned. End cleanly with the close line.';
} else {
  modeInstruction = 'MODE B — RETURN CHAT. Priorities and sources already exist. Open with one line of context from the priorities doc. 2-4 turns max. Goal: identify what the user wants more of, or what changed. End with the close line.';
}

const followedStr = followed.length > 0
  ? followed.map(s => `- ${s.name} (${s.url}) [${s.category || 'uncategorized'}]`).join('\n')
  : 'None';

const naylistedStr = naylisted.length > 0
  ? naylisted.map(s => `- ${s.name} (${s.url})`).join('\n')
  : 'None';

return [{ json: {
  query: message,
  sessionId,
  userId,
  clientId,
  mode,
  modeInstruction,
  priorities,
  followedSources: followedStr,
  naylistedSources: naylistedStr,
  followedCount: followed.length,
  naylistedCount: naylisted.length,
  history
}}];

let raw = $input.first().json.output;
const sessionId = $('Build Prompt').first().json.sessionId;
const userId = $('Build Prompt').first().json.userId;
const clientId = $('Build Prompt').first().json.clientId;

let parsed;
if (typeof raw === 'object' && raw !== null) {
  parsed = raw;
} else {
  let text = String(raw || '').trim();
  text = text.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?\s*```\s*$/, '').trim();
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    const match = text.match(/\{[\s\S]*"message"[\s\S]*\}$/);
    if (match) {
      try { parsed = JSON.parse(match[0]); } catch (e2) { parsed = null; }
    }
    if (!parsed) {
      parsed = { message: text.replace(/\{[\s\S]*$/, '').trim(), done: false };
    }
  }
}

return [{ json: {
  message: parsed.message || String(raw),
  done: parsed.done === true,
  priorities: parsed.priorities || null,
  sources: parsed.sources || [],
  sessionId,
  userId,
  clientId
}}];

return [{ json: {
  session_id: $json.sessionId,
  message: $json.message,
  done: false,
  events: []
}}];

const priorities = $json.priorities || '';
const sources = $json.sources || [];
const userId = $json.userId;
const clientId = $json.clientId;
const sessionId = $json.sessionId;
const message = $json.message;

const escapedPriorities = priorities.replace(/'/g, "''");

const prioritiesQuery = priorities
  ? `UPDATE portal_user SET settings = jsonb_set(jsonb_set(COALESCE(settings, '{}'), '{radar}', COALESCE(settings->'radar', '{}')), '{radar,priorities_markdown}', to_jsonb('${escapedPriorities}'::text)) WHERE n8n_user_id = '${userId}'::uuid`
  : 'SELECT 1';

let sourcesQuery = 'SELECT 1 WHERE false';
if (sources.length > 0) {
  const values = sources.map(s => {
    const esc = v => (v || '').replace(/'/g, "''");
    return `('${userId}'::uuid, '${esc(clientId)}', '${esc(s.url)}', '${esc(s.name)}', '${esc(s.category)}', '${esc(s.tone_tag)}', '${esc(s.because_quote)}', 'proposed', 'unknown')`;
  }).join(', ');
  sourcesQuery = `INSERT INTO radar_sources (user_id, client_id, url, name, category, tone_tag, because_quote, status, viability) VALUES ${values}`;
}

const events = [];
if (priorities) events.push({ type: 'tool_call', name: 'updatePriorities', args: {} });
sources.forEach(s => events.push({ type: 'tool_call', name: 'proposeSource', args: { name: s.name, url: s.url } }));

return [{ json: { prioritiesQuery, sourcesQuery, message, sessionId, events } }];

const prev = $('Prepare Curation').first().json;
return [{ json: {
  session_id: prev.sessionId,
  message: prev.message,
  done: true,
  events: prev.events
}}];

